INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bab9442b-c15d-4ead-b5e1-0a31ce1b4841',
  '00000000-0000-0000-0000-000000000001',
  $escape$Snowflake — Warehouse vs Database: Why Your Queries Think in Columns, Not Rows$escape$,
  $escape$Snowflake separates compute (Virtual Warehouses) from storage (Databases) entirely — a distinction most RDBMS users trip over. Your DATABASE holds schemas, tables, and data persisted in Snowflake's internal micro-partition format. Your VIRTUAL WAREHOUSE is the compute cluster that queries it. They scale independently.

Snowflake is pure OLAP. Every table is columnar: micro-partitions (~16MB compressed) store values column-by-column, with min/max metadata per column per partition. A query like `SELECT SUM(revenue) FROM orders WHERE region = 'US'` only scans the `revenue` and `region` columns across relevant partitions — row-based engines like PostgreSQL would scan every column in every qualifying row.

This is why Snowflake clusters tables by high-cardinality filter columns using `CLUSTER BY` — it co-locates similar values across partitions, enabling aggressive partition pruning. For point lookups or high-frequency transactional writes (INSERT one row at a time), Snowflake is the wrong tool — micro-partition overhead makes it expensive. Design for bulk loads via COPY INTO and analytical aggregations, not OLTP patterns.$escape$,
  $escape$-- Check partition pruning effectiveness on a clustered table
SELECT
    query_id,
    partitions_scanned,
    partitions_total,
    ROUND(partitions_scanned / partitions_total * 100, 2) AS pct_scanned
FROM snowflake.account_usage.query_history
WHERE query_text ILIKE '%orders%'
  AND start_time >= DATEADD('day', -1, CURRENT_TIMESTAMP())
ORDER BY start_time DESC
LIMIT 10;

-- Define clustering key to minimize partition scans
ALTER TABLE orders CLUSTER BY (region, order_date);$escape$,
  $escape$sql$escape$,
