INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f57349c7-ca9d-4ed7-b106-e36c3f0819ac',
  '00000000-0000-0000-0000-000000000001',
  $escape$Snowflake's Power Features: Virtual Warehouses, Zero-Copy Cloning, Time Travel, and Data Sharing$escape$,
  $escape$Snowflake separates compute from storage via Virtual Warehouses — independent MPP clusters you spin up per workload. A `WAREHOUSE_SIZE = LARGE` runs 8 nodes; suspend it when idle with `AUTO_SUSPEND = 60` to pay only for active seconds. Zero-copy cloning creates instant metadata-only snapshots of tables, schemas, or entire databases — no data duplication until divergent writes occur. Use `CREATE TABLE orders_staging CLONE orders` to give every dev a full production dataset without storage cost. Time Travel lets you query or restore historical data up to 90 days back (Enterprise tier). `SELECT * FROM orders AT (TIMESTAMP => '2025-01-01 09:00:00'::TIMESTAMP)` or `UNDROP TABLE orders` after accidental deletion. Data Sharing bypasses ETL entirely — publish a named Share, grant object privileges, and consumers in other Snowflake accounts query live data directly via their own Virtual Warehouse. No data movement, no copies, billing stays separate. These four features together eliminate entire infrastructure categories: staging environments, backup pipelines, and cross-org data transfer jobs.$escape$,
  $escape$-- Warehouse with auto-suspend
CREATE OR REPLACE WAREHOUSE analytics_wh
  WAREHOUSE_SIZE = 'MEDIUM'
  AUTO_SUSPEND = 60
  AUTO_RESUME = TRUE;

-- Zero-copy clone for dev environment
CREATE DATABASE prod_clone CLONE prod;

-- Time Travel query
SELECT * FROM orders
  AT (OFFSET => -3600);  -- 1 hour ago

-- Restore dropped table
UNDROP TABLE orders;

-- Data Sharing
CREATE SHARE analytics_share;
GRANT USAGE ON DATABASE prod TO SHARE analytics_share;
GRANT SELECT ON ALL TABLES IN SCHEMA prod.public TO SHARE analytics_share;
ALTER SHARE analytics_share ADD ACCOUNTS = org2.account1;$escape$,
