INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '397e4cc5-8e16-40d9-9e27-2aa8a964df79',
  '00000000-0000-0000-0000-000000000001',
  $escape$Snowflake vs BigQuery — Slots, Partitioning, and Clustering for the Snowflake Developer$escape$,
  $escape$Coming from Snowflake's virtual warehouse model, BigQuery's compute abstraction is disorienting. BigQuery has no warehouses — compute is measured in slots (units of CPU/RAM/IO). On-demand pricing bills per TB scanned; flat-rate buys slot commitments in 100-slot blocks with 1yr/3yr reservations. Snowflake's credit-based warehouses map closest to BigQuery's flat-rate model — both decouple storage from compute, but Snowflake lets you size and suspend explicitly.

Partitioning in BigQuery is opt-in and manual. You declare PARTITION BY at CREATE TABLE time using a DATE, TIMESTAMP, or integer-range column. There's no equivalent to Snowflake's automatic micro-partitioning — if you skip PARTITION BY, BigQuery scans the full table. Partition pruning only kicks in when your WHERE clause filters on the partition column, mirroring Snowflake's metadata pruning behavior but requiring deliberate schema design.

Clustering supports up to 4 columns and auto-recluster as data grows — no manual ALTER TABLE RECLUSTER like Snowflake requires. For cost control, query INFORMATION_SCHEMA.JOBS_BY_PROJECT to audit slot usage and bytes billed, the BigQuery analog to Snowflake's QUERY_HISTORY and RESOURCE_MONITOR.$escape$,
  $escape$-- Snowflake: micro-partitions automatic, clustering explicit
CREATE TABLE events (
  event_id    VARCHAR,
  user_id     VARCHAR,
  occurred_at TIMESTAMP_NTZ,
  event_type  VARCHAR
) CLUSTER BY (event_type, DATE(occurred_at));

-- BigQuery equivalent: partitioning AND clustering must be declared
CREATE TABLE `project.dataset.events` (
  event_id    STRING,
  user_id     STRING,
  occurred_at TIMESTAMP,
  event_type  STRING
)
PARTITION BY DATE(occurred_at)
CLUSTER BY event_type, user_id;$escape$,
  $escape$sql$escape$,
