INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2498b183-fbbc-4c9c-9dc3-3942df75f31b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Snowflake to Databricks — Mapping Delta Lake, Unity Catalog, and Photon to What You Already Know$escape$,
  $escape$Coming from Snowflake, Databricks' Delta Lake will feel familiar in structure but foreign in operational overhead. Delta Lake is the storage layer — think of it as Snowflake's micro-partition engine, except built on open Parquet + transaction logs written to your own cloud storage. Unlike Snowflake's automatic clustering, you explicitly call OPTIMIZE on Delta tables and define Z-ordering columns yourself.

Time Travel syntax maps almost 1:1: Snowflake's `AT(TIMESTAMP => '2024-01-01'::TIMESTAMP)` becomes `TIMESTAMP AS OF '2024-01-01'` in Delta SQL. Retention is log-based via `delta.logRetentionDuration`, not Snowflake's managed 0–90 day Fail-safe window.

Unity Catalog mirrors Snowflake's three-level namespace (`database.schema.table` → `catalog.schema.table`). The hierarchy transfers cleanly, but access control shifts from Snowflake's RBAC (`GRANT SELECT ON TABLE`) to Unity Catalog's attribute-based policies scoped at the metastore level.

Photon, Databricks' vectorized C++ execution engine, is the closest analog to Snowflake's internal query optimizer and pruning engine — no manual configuration, just select a Photon-enabled cluster. Unlike Snowflake virtual warehouses, you're sizing clusters, not credit-per-second compute tiers.$escape$,
  $escape$-- Snowflake: Time Travel
SELECT * FROM orders AT(TIMESTAMP => '2024-01-01 00:00:00'::TIMESTAMP_NTZ);

-- Delta Lake equivalent (Databricks SQL)
SELECT * FROM orders TIMESTAMP AS OF '2024-01-01 00:00:00';

-- Delta: manual compaction + Z-ordering (Snowflake handles this automatically via clustering keys)
OPTIMIZE catalog.sales.orders ZORDER BY (customer_id, order_date);

-- Delta: inspect table history (analogous to Snowflake ACCOUNT_USAGE.ACCESS_HISTORY)
DESCRIBE HISTORY catalog.sales.orders;

-- Unity Catalog: grant (Snowflake RBAC equivalent)
GRANT SELECT ON TABLE catalog.sales.orders TO `analyst@company.com`;$escape$,
  $escape$sql$escape$,
