INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '350f0a0e-bf68-4379-b3de-303ae1825daf',
  '00000000-0000-0000-0000-000000000001',
  $escape$Snowflake + dbt — Why ELT Beats ETL in the Modern Data Stack$escape$,
  $escape$ETL pre-transforms data before loading — a constraint born when warehouse compute was expensive and scarce. Snowflake inverts this: load raw data first via COPY INTO or Snowpipe, then transform it inside the warehouse using elastic Virtual Warehouses.

This is ELT, and Snowflake's architecture makes it natural. Raw data lands in a staging layer — typically a dedicated RAW_DB database — and dbt owns the T. dbt models compile to SQL executed directly against Snowflake, benefiting from columnar storage and automatic micro-partition pruning. Each model maps to a VIEW, TABLE, or INCREMENTAL materialization. INCREMENTAL models emit MERGE statements, using a unique_key or a watermark against Snowflake STREAMS to process only new or changed records.

The compounding advantages: Time Travel (up to 90 days on Enterprise) gives you a full audit trail without extra tooling. Zero-copy CLONE spins up isolated dev and staging environments instantly. And when transformation jobs slow down, you scale by bumping the Virtual Warehouse size — no pipeline rewrite, no data movement.$escape$,
  $escape$-- models/marts/orders_fact.sql
{{ config(
    materialized='incremental',
    unique_key='order_id',
    cluster_by=['order_date']
) }}

SELECT
    order_id,
    customer_id,
    order_date::DATE        AS order_date,
    total_amount_usd,
    _loaded_at
FROM {{ source('raw', 'orders') }}
{% if is_incremental() %}
WHERE _loaded_at > (SELECT MAX(_loaded_at) FROM {{ this }})
{% endif %}$escape$,
  $escape$sql$escape$,
