INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '59b961f4-101f-4365-a909-e5dbea8edae8',
  '00000000-0000-0000-0000-000000000001',
  $escape$Snowflake Cost Management — Estimating Query Credits Before They Hit Your Bill$escape$,
  $escape$Snowflake bills compute in credits per second (60s minimum per warehouse resume). A single runaway query on an XL warehouse burns 8 credits/hour — knowing cost before execution matters. Use EXPLAIN to inspect logical partitions touched without running the query, then cross-reference SNOWFLAKE.ACCOUNT_USAGE.QUERY_HISTORY for actual credits_used_cloud_services on historical runs. Materialized views cut repeated scan costs: Snowflake auto-refreshes them in background jobs (charged separately at your warehouse size), but queries against them skip the full base table scan entirely, often eliminating 80–90% of bytes_scanned. The catch — MV maintenance credits accumulate even when nobody queries the view, so apply them selectively on high-frequency aggregation patterns. Use RESOURCE_MONITOR at the account or warehouse level to enforce hard credit caps and trigger SUSPEND or NOTIFY actions before budgets blow. For per-query attribution in shared warehouses, filter QUERY_HISTORY by user_name and warehouse_name and join against METERING_HISTORY to convert wall-clock time to fractional credit spend. Always cluster your base tables on filter columns before creating MVs — unclustered sources force full micro-partition scans on every MV refresh.$escape$,
  $escape$-- Top 10 costliest queries in last 7 days with partition efficiency
SELECT
    query_id,
    LEFT(query_text, 80)          AS query_preview,
    warehouse_name,
    ROUND(execution_time / 1000, 1) AS exec_seconds,
    partitions_scanned,
    partitions_total,
    ROUND(bytes_scanned / 1e9, 2)  AS gb_scanned,
    credits_used_cloud_services
FROM snowflake.account_usage.query_history
WHERE start_time >= DATEADD('day', -7, CURRENT_TIMESTAMP())
  AND execution_status = 'SUCCESS'
  AND warehouse_size IS NOT NULL
ORDER BY execution_time DESC
LIMIT 10;$escape$,
  $escape$sql$escape$,
