INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd7cc8bb3-8416-4d54-9703-0c85cccf4078',
  '00000000-0000-0000-0000-000000000001',
  $escape$Snowflake Data Quality — Nulls, Deduplication, and Constraint Enforcement That Actually Works$escape$,
  $escape$Snowflake enforces NOT NULL and UNIQUE constraints syntactically but not physically — they're informational only and never block inserts. Your data quality layer must be explicit. For null handling, use ZEROIFNULL() and NVL2() at load time, or define column defaults via ALTER TABLE ... ALTER COLUMN ... SET DEFAULT. For deduplication, QUALIFY with ROW_NUMBER() is the idiomatic pattern: partition by your natural key, order by ingestion timestamp DESC, and filter WHERE row_num = 1. Wrap this in a MERGE statement targeting your target table to make it idempotent. For constraint enforcement, lean on Data Metric Functions (DMFs) — introduced in 2024 — which let you attach metric functions like SNOWFLAKE.CORE.NULL_COUNT and SNOWFLAKE.CORE.DUPLICATE_COUNT directly to tables and schedule them via DATA METRIC SCHEDULE. These run serverlessly and write results to SNOWFLAKE.LOCAL.DATA_QUALITY_MONITORING_RESULTS, queryable via the INFORMATION_SCHEMA. Pair DMFs with Snowflake Alerts to trigger notifications when null rates or duplicate counts breach thresholds — no external orchestrator needed.$escape$,
  $escape$-- Idempotent dedup + MERGE using QUALIFY
MERGE INTO orders_clean AS tgt
USING (
  SELECT *
  FROM (
    SELECT *,
      ROW_NUMBER() OVER (
        PARTITION BY order_id
        ORDER BY _loaded_at DESC
      ) AS row_num
    FROM orders_raw
  )
  WHERE row_num = 1
) AS src
ON tgt.order_id = src.order_id
WHEN MATCHED THEN UPDATE SET tgt.status = src.status, tgt.updated_at = src.updated_at
WHEN NOT MATCHED THEN INSERT VALUES (src.order_id, src.status, src.updated_at);

-- Attach a DMF to enforce null monitoring
ALTER TABLE orders_clean
  ADD DATA METRIC FUNCTION SNOWFLAKE.CORE.NULL_COUNT
  ON (order_id)
  DATA METRIC SCHEDULE = 'TRIGGER_ON_CHANGES';$escape$,
