INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '65a7fa40-624d-4fc3-866d-4be62094fe3d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Snowflake Access Control — RBAC, Column Masking, and Row Access Policies in One Stack$escape$,
  $escape$Snowflake's access control runs three layers deep. First, RBAC: every privilege flows through roles, never directly to users. Use GRANT PRIVILEGE ON OBJECT TO ROLE, then GRANT ROLE TO USER. Roles compose hierarchically — ANALYST can inherit READ_PROD via role hierarchy without duplicating grants. Second, column-level security via Dynamic Data Masking: attach a masking policy to a column, and Snowflake evaluates it at query time based on the querying role. Unmasked data never leaves the warehouse for unauthorized roles — the policy runs server-side. Third, row-level security via Row Access Policies: attach a policy function to a table that returns a boolean filter. The WHERE clause is injected transparently — users can't bypass it with UNION or subqueries. All three compose cleanly: a user can have row-filtered access to a table where salary columns are masked. Crucially, these policies are centrally managed objects — change the policy once, it propagates to every table it's attached to. No need to rebuild views.$escape$,
  $escape$-- 1. Role hierarchy
CREATE ROLE analyst;
GRANT ROLE read_prod TO ROLE analyst;
GRANT ROLE analyst TO USER jane;

-- 2. Column masking policy (hide salary for non-HR roles)
CREATE MASKING POLICY mask_salary AS (val NUMBER)
  RETURNS NUMBER ->
  CASE WHEN CURRENT_ROLE() = 'HR_ROLE' THEN val ELSE -1 END;

ALTER TABLE employees MODIFY COLUMN salary
  SET MASKING POLICY mask_salary;

-- 3. Row access policy (each user sees only their region)
CREATE ROW ACCESS POLICY region_filter AS (region STRING)
  RETURNS BOOLEAN ->
  region = CURRENT_ROLE();

ALTER TABLE sales ADD ROW ACCESS POLICY region_filter ON (region);$escape$,
  $escape$sql$escape$,
