INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '63dee505-6134-4730-a553-e09dd8d7cd50',
  '00000000-0000-0000-0000-000000000001',
  $escape$Snowflake Query Performance — Result Cache, Clustering, and Materialized Views$escape$,
  $escape$Snowflake's result cache is your fastest optimization: identical queries return in milliseconds without consuming credits, as long as the underlying data hasn't changed and the query runs within 24 hours. No config needed — it's automatic. But it only fires on exact query matches, so parameterized queries or slight variations bypass it entirely.

For repetitive aggregation workloads, materialized views let Snowflake incrementally maintain precomputed results. Unlike traditional DBs, Snowflake auto-refreshes them in the background when base table DML occurs — you never manually REFRESH. However, they're best for high-frequency, low-cardinality aggregations; avoid them on frequently mutated tables with wide fan-out.

For large table scans, cluster keys dramatically reduce partition pruning cost. Use SYSTEM$CLUSTERING_INFORMATION() to inspect cluster depth before committing. Prefer natural sort keys (e.g. EVENT_DATE) over synthetic ones. Combine with query profiling via EXPLAIN or the Query Profile UI to identify the exact partition scan overhead before and after clustering.$escape$,
  $escape$-- Check result cache hit
SELECT QUERY_ID, QUERY_TEXT, EXECUTION_STATUS,
       BYTES_SCANNED, PARTITIONS_SCANNED,
       IS_CLIENT_GENERATED_STATEMENT
FROM SNOWFLAKE.ACCOUNT_USAGE.QUERY_HISTORY
WHERE START_TIME >= DATEADD('hour', -1, CURRENT_TIMESTAMP())
  AND QUERY_TEXT ILIKE '%your_table%'
ORDER BY START_TIME DESC;

-- Inspect clustering health before adding cluster key
SELECT SYSTEM$CLUSTERING_INFORMATION('your_db.your_schema.events', '(event_date)');

-- Create a materialized view for hourly aggregation
CREATE MATERIALIZED VIEW mv_hourly_events AS
SELECT DATE_TRUNC('hour', event_ts) AS hour_bucket,
       event_type,
       COUNT(*) AS event_count
FROM events
GROUP BY 1, 2;$escape$,
