INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bc73aa2d-cd9a-403a-bc4d-c98670644e47',
  '00000000-0000-0000-0000-000000000001',
  $escape$Snowflake Data Sharing — Cross-Account Access Without Moving a Single Byte$escape$,
  $escape$Snowflake's Data Sharing works by granting read access to your storage layer directly — no ETL, no replication, no latency. The provider creates a SHARE object, attaches database objects to it, then grants access to a consumer account. The consumer mounts it as a read-only database instantly.

Secure views are the critical safety layer here. A regular view exposes its definition to the consumer via SHOW VIEWS or GET_DDL. A SECURE VIEW hides the definition entirely, preventing inference of underlying table structure or filter logic. Always use CREATE SECURE VIEW when sharing computed or masked data.

For the Snowflake Marketplace, you publish a listing backed by a share. Consumers can be any Snowflake account — even on different cloud regions via Replication-enabled shares. Use DATA_SHARING_USAGE schema in SNOWFLAKE database to audit which consumers queried your share and when.

One sharp edge: shares cannot include stages, pipes, tasks, or UDFs. If your consumers need transformed data, materialize it into a dedicated sharing schema via a scheduled task before attaching to the share.$escape$,
  $escape$-- Provider account: create and populate a share
CREATE SHARE product_analytics_share;
GRANT USAGE ON DATABASE analytics_db TO SHARE product_analytics_share;
GRANT USAGE ON SCHEMA analytics_db.public TO SHARE product_analytics_share;

-- Use SECURE VIEW to hide filter logic from consumer
CREATE SECURE VIEW analytics_db.public.daily_metrics AS
  SELECT date, event_type, COUNT(*) AS event_count
  FROM raw_events
  WHERE tenant_id = CURRENT_ACCOUNT()  -- hidden from consumer
  GROUP BY 1, 2;

GRANT SELECT ON VIEW analytics_db.public.daily_metrics TO SHARE product_analytics_share;

-- Grant to consumer account (get account ID from partner)
ALTER SHARE product_analytics_share ADD ACCOUNTS = ORG1.CONSUMER_ACCT;

-- Consumer account: mount the share
CREATE DATABASE metrics_from_provider FROM SHARE ORG1.PROVIDER_ACCT.product_analytics_share;$escape$,
  $escape$sql$escape$,
