INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6f6ad9f4-3f32-45ba-bd9c-8caeacee6728',
  '00000000-0000-0000-0000-000000000001',
  $escape$Snowflake Incremental Loading — Append, Upsert, and MERGE Patterns$escape$,
  $escape$Snowflake's micro-partition architecture makes append-only loads extremely cheap — INSERT INTO ... SELECT from a stage hits zero rewrite cost since Snowflake never mutates existing partitions. For immutable event streams (logs, clickstreams), lean into this: stage raw JSON in an external stage, COPY INTO a raw table, done.

Upsert patterns require MERGE. Snowflake's MERGE is ANSI-compliant but has a critical gotcha: if your source has duplicate keys, you'll hit 'non-deterministic MERGE' errors. Deduplicate with a CTE using ROW_NUMBER() OVER (PARTITION BY id ORDER BY updated_at DESC) before merging.

For CDC from upstream databases (Debezium → Kafka → Snowflake), the pattern is: land raw CDC events into a staging table preserving op type (I/U/D), then MERGE into the target using WHEN MATCHED AND src.op = 'D' THEN DELETE. Snowflake Streams + Tasks automate this natively — a Stream on the staging table tracks DML changes since the last consume offset, and a Task fires the MERGE on a schedule or via SYSTEM$STREAM_HAS_DATA(). This eliminates manual watermark tracking entirely.$escape$,
  $escape$-- CDC upsert via Snowflake Stream + MERGE
MERGE INTO orders AS tgt
USING (
  SELECT *,
         ROW_NUMBER() OVER (PARTITION BY order_id ORDER BY _metadata_timestamp DESC) AS rn
  FROM orders_cdc_stream
) AS src ON tgt.order_id = src.order_id AND src.rn = 1
WHEN MATCHED AND src.op = 'D' THEN DELETE
WHEN MATCHED AND src.op = 'U' THEN UPDATE SET
  tgt.status = src.status,
  tgt.updated_at = src.updated_at
WHEN NOT MATCHED AND src.op = 'I' THEN INSERT
  (order_id, status, created_at, updated_at)
  VALUES (src.order_id, src.status, src.created_at, src.updated_at);$escape$,
  $escape$sql$escape$,
