INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'afafbf1c-9442-4171-bafe-78e64a75538e',
  '00000000-0000-0000-0000-000000000001',
  $escape$Snowflake VARIANT — Querying Nested JSON and Evolving Parquet Schemas Without Breaking Pipelines$escape$,
  $escape$Snowflake stores semi-structured data in VARIANT columns — a self-describing binary format accepting JSON, Avro, or Parquet up to 16 MB per value. Colon notation (`rec:user:id`) and bracket notation (`rec['user']['id']`) are interchangeable for path traversal; leaf values return as VARIANT by default, so always cast explicitly with `::STRING` or `::NUMBER` to avoid silent type mismatches downstream.

For arrays, LATERAL FLATTEN is the workhorse — it explodes nested arrays into rows, exposing `VALUE`, `INDEX`, `KEY`, and `PATH` columns. Add `RECURSIVE => TRUE` to traverse arbitrarily deep structures in one pass.

Schema evolution is handled via `COPY INTO` with the `EVOLVE SCHEMA = TRUE` copy option (GA since 2024) — new columns in incoming Parquet files are automatically appended to the target table, no manual `ALTER TABLE` needed. Pair with `INFER_SCHEMA` on a staged file to preview inferred column definitions before committing a load.

For production pipelines: land raw JSON into VARIANT, then project typed views using `$1:field::TYPE` aliases. This decouples upstream schema drift from downstream consumers — the view breaks, not the base table.$escape$,
  $escape$-- Infer schema from staged Parquet before loading
SELECT * FROM TABLE(INFER_SCHEMA(
  LOCATION => '@my_stage/events/',
  FILE_FORMAT => 'my_parquet_fmt'
));

-- Load Parquet with automatic schema evolution
COPY INTO analytics.events
FROM @my_stage/events/
FILE_FORMAT = (TYPE = PARQUET)
MATCH_BY_COLUMN_NAME = CASE_INSENSITIVE
COPY_OPTIONS = (EVOLVE_SCHEMA = TRUE);

-- Query nested JSON with explicit casting + FLATTEN
SELECT
  rec:user:id::STRING       AS user_id,
  rec:metadata:ts::TIMESTAMP AS event_ts,
  f.value::STRING           AS tag
FROM raw_events,
  LATERAL FLATTEN(input => rec:tags) f
WHERE rec:event_type::STRING = 'click';$escape$,
