INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '761a5ff9-09d4-4770-b2c8-11d89d92619d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Snowflake Integration — Wiring dbt, Airflow, BI Tools, and Reverse ETL the Right Way$escape$,
  $escape$Snowflake's integration story centers on a service account pattern: create a dedicated role per tool, grant only the warehouses and schemas it needs, and never share credentials. For dbt, configure `profiles.yml` with `authenticator: externalbrowser` or key-pair auth — avoid password auth in CI. Set `query_tag` in your dbt profile so every query is traceable in `QUERY_HISTORY`. With Airflow, use the `SnowflakeOperator` from `apache-airflow-providers-snowflake` and store your connection in Airflow's encrypted secrets backend, not `airflow.cfg`. For BI tools like Tableau or Looker, provision a dedicated `REPORTER` role with `SELECT` on `INFORMATION_SCHEMA` and your reporting schema — enable query result caching at the warehouse level to cut costs. For reverse ETL (Census, Hightouch), create a dedicated `REVERSE_ETL_WH` warehouse sized XS with auto-suspend at 60 seconds; these tools run frequent small queries and a larger warehouse burns credits fast. Lock down with `NETWORK POLICY` to allowlist tool IPs. Audit all of this via `SNOWFLAKE.ACCOUNT_USAGE.ACCESS_HISTORY`.$escape$,
  $escape$-- One-time setup: dedicated role + warehouse for dbt
CREATE ROLE dbt_role;
CREATE WAREHOUSE dbt_wh
  WAREHOUSE_SIZE = 'SMALL'
  AUTO_SUSPEND = 120
  AUTO_RESUME = TRUE;

GRANT USAGE ON WAREHOUSE dbt_wh TO ROLE dbt_role;
GRANT USAGE ON DATABASE analytics TO ROLE dbt_role;
GRANT USAGE ON ALL SCHEMAS IN DATABASE analytics TO ROLE dbt_role;
GRANT SELECT ON ALL TABLES IN SCHEMA analytics.raw TO ROLE dbt_role;
GRANT CREATE TABLE ON SCHEMA analytics.transformed TO ROLE dbt_role;

-- Tag every dbt session for observability
ALTER SESSION SET QUERY_TAG = 'dbt_prod';$escape$,
